INSERT INTO `announcements` (`id`, `title`, `published`, `content`, `modified`, `created`) VALUES
(10, 'Reglas Básicas Generales', 1, '<p>Reglas B&aacute;sicas. <strong>Pocas pero precisas:</strong></p>\r\n\r\n<p>- Prohibido acortar doble. Tanto de este como de otro acortador.</p>\r\n\r\n<p>- Prohibido Acortar y Publicar Noticias Falsas, sobre todo de Muertes y er&oacute;ticas.</p>\r\n\r\n<p>- Tener al menos la mitad del m&iacute;nimo retiro generado como editor para tener derecho a cobrar los Referidos.</p>\r\n\r\n<p>- El usuario que no ayude a sus referidos y este ande perdido y cometiendo errores por desconocimiento, se le retirar&aacute; de referido el usuario incumplidor.</p>\r\n\r\n<p>En el caso de las prohibiciones, por primera vez se le eliminar&aacute; el dinero generado por los enlaces prohibidos y se le llamar&aacute; la atenci&oacute;n. Si al descontar los ingresos ilegales no llega al m&iacute;nimo de retiro se le reembolsar&aacute; a la cuenta y una vez que llegue al m&iacute;nimo es que podr&aacute; volver a retirar. Por 2da vez con la misma violaci&oacute;n ser&aacute; eliminada su cuenta sin derecho a reclamos ni reembolsos de lo generado.</p>\r\n', '2021-06-04 15:53:00', '2021-06-04 15:53:00');
