(218, 'withdraw_methods', '[{\"id\":\"paypal\",\"name\":\"PayPal\",\"status\":\"0\",\"amount\":\"50\",\"image\":\"\\/assets\\/methods\\/paypal.png\",\"description\":\"- Para PayPal debes a\\u00f1adir tu correo vinculado a la cuenta.\"},{\"id\":\"payza\",\"name\":\"Payza\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/payza.png\",\"description\":\"- For Payza, add your email.\"},{\"id\":\"skrill\",\"name\":\"Skrill\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/skrill.png\",\"description\":\"- For Skrill, add your email.\"},{\"id\":\"bitcoin\",\"name\":\"Bitcoin\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/bitcoin.png\",\"description\":\"- For Bitcoin add your wallet address.\"},{\"id\":\"webmoney\",\"name\":\"Web Money\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/webmoney.png\",\"description\":\"- For Web Money, add your purse.\"},{\"id\":\"perfectmoney\",\"name\":\"Perfect Money\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/perfectmoney.png\",\"description\":\"- For Perfect Money add your email.\"},{\"id\":\"payeer\",\"name\":\"Payeer\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/payeer.png\",\"description\":\"- For Payeer add account, e-mail or phone number.\"},{\"id\":\"banktransfer\",\"name\":\"Bank Transfer\",\"status\":\"0\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/banktransfer.png\",\"description\":\"- For bank transfer add your account holder name, Bank Name, City\\/Town, Country, Account number, SWIFT, IBAN and Account currency\"},{\"id\":\"mlc-tarjeta\",\"name\":\"Transferencia en MLC\",\"status\":\"1\",\"amount\":\"10\",\"image\":\"\\/assets\\/methods\\/banktransfer.png\",\"description\":\"- Para MLC introducir Banco y N\\u00famero de la Tarjeta de MLC.\"},{\"id\":\"usdt\",\"name\":\"USDT\",\"status\":\"1\",\"amount\":\"5\",\"image\":\"\\/assets\\/methods\\/bitcoin.png\",\"description\":\"- Para USDT introduce tu direcci\\u00f3n de la wallet, debe ser USDT TRC20.\"},{\"id\":\"recargas\",\"name\":\"Recargas a Cubacel\",\"status\":\"1\",\"amount\":\"5\",\"image\":\"\",\"description\":\"- Para Recargas Telef\\u00f3nicas ponga el N\\u00famero a recargar. El monto a recargar ser\\u00e1 el del saldo retirado a raz\\u00f3n de 1 USD x 48 CUP. Recargas por encima de 22 USD caen con Bono en Promociones.\"}]'),
